#include "veml7700.h"
#include <Wire.h>
#include <Adafruit_VEML7700.h>
static Adafruit_VEML7700 veml;
static float _lux=0,_w=0,_als=0;
static unsigned long _last=0;
void veml7700_setup(){Wire.begin();if(!veml.begin()){Serial.println("[veml7700] Fail!");return;}veml.setGain(VEML7700_GAIN_1);veml.setIntegrationTime(VEML7700_IT_800MS);Serial.println("[veml7700] OK");}
void veml7700_loop(){if(millis()-_last<1000)return;_last=millis();_lux=veml.readLux();_w=veml.readWhite();_als=veml.readALS();}
float veml7700_get_lux(){return _lux;}
float veml7700_get_white(){return _w;}
float veml7700_get_als(){return _als;}
